// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryLanguage;
import org.eclipse.rdf4j.query.TupleQuery;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.DefaultEvaluationStrategyFactory;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.Repository;
import org.eclipse.rdf4j.repository.RepositoryConnection;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * End-to-end equivalence test for the leapfrogging merge join in standard evaluation mode: a merge join over two
 * ordered LMDB scans must produce identical results whether the advisory statement-level seek is enabled or disabled,
 * and identical to the synthetically computed expected join result.
 */
public class LmdbMergeJoinLeapfrogTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String NS = "http://example.com/";
	private static final IRI DENSE_PREDICATE = VF.createIRI(NS, "p");
	private static final IRI SPARSE_PREDICATE = VF.createIRI(NS, "q");

	private static final int DENSE_SIZE = 4000;
	// every 8th dense subject also has a sparse statement: an 8x cardinality ratio keeps the optimizer's merge
	// join selection (limit 10x) while making the next match far enough away for seeks to trigger
	private static final int SPARSE_STRIDE = 8;

	private static final String QUERY = "SELECT ?s ?o ?v WHERE { ?s <" + SPARSE_PREDICATE + "> ?v . ?s <"
			+ DENSE_PREDICATE + "> ?o }";

	@TempDir
	File dataDir;

	private Repository lmdbRepository;

	@BeforeEach
	public void setUp() {
		LmdbStore store = new LmdbStore(new File(dataDir, "lmdb"), new LmdbStoreConfig("spoc,posc"));
		// the LMDB-specific optimizer pipelines currently never mark merge joins (the standard pipeline is
		// deliberately order-blind); the default strategy factory uses the order-aware standard pipeline, which
		// is the configuration the generic merge join leapfrog targets
		store.setEvaluationStrategyFactory(new DefaultEvaluationStrategyFactory());
		lmdbRepository = new SailRepository(store);

		addTestData(lmdbRepository);
	}

	@AfterEach
	public void tearDown() {
		System.clearProperty("rdf4j.lmdb.statementSeek.enabled");
		if (lmdbRepository != null) {
			lmdbRepository.shutDown();
		}
	}

	private void addTestData(Repository repository) {
		try (RepositoryConnection connection = repository.getConnection()) {
			connection.begin();
			for (int i = 0; i < DENSE_SIZE; i++) {
				IRI subject = VF.createIRI(NS, "subject-" + i);
				connection.add(subject, DENSE_PREDICATE, VF.createIRI(NS, "object-" + i));
				if (i % SPARSE_STRIDE == 0) {
					connection.add(subject, SPARSE_PREDICATE, VF.createIRI(NS, "value-" + i));
				}
			}
			connection.commit();
		}
	}

	private List<String> expectedResults() {
		List<String> expected = new ArrayList<>();
		for (int i = 0; i < DENSE_SIZE; i += SPARSE_STRIDE) {
			expected.add(VF.createIRI(NS, "subject-" + i) + "|" + VF.createIRI(NS, "object-" + i) + "|"
					+ VF.createIRI(NS, "value-" + i));
		}
		return expected.stream().sorted().collect(Collectors.toList());
	}

	private List<String> query(Repository repository) {
		try (RepositoryConnection connection = repository.getConnection()) {
			TupleQuery tupleQuery = connection.prepareTupleQuery(QueryLanguage.SPARQL, QUERY);
			List<String> result = new ArrayList<>();
			try (var iterator = tupleQuery.evaluate()) {
				while (iterator.hasNext()) {
					BindingSet bindings = iterator.next();
					result.add(bindings.getValue("s") + "|" + bindings.getValue("o") + "|" + bindings.getValue("v"));
				}
			}
			return result.stream().sorted().collect(Collectors.toList());
		}
	}

	@Test
	public void mergeJoinIsUsedAndSeekPreservesResults() {
		String plan;
		try (RepositoryConnection connection = lmdbRepository.getConnection()) {
			TupleQuery tupleQuery = connection.prepareTupleQuery(QueryLanguage.SPARQL, QUERY);
			plan = tupleQuery.explain(Explanation.Level.Executed).toString();
		}
		assertThat(plan)
				.as("the join must actually run as a merge join, otherwise this test exercises nothing")
				.contains("InnerMergeJoinIterator");

		List<String> baseline = expectedResults();
		assertThat(baseline).hasSize(DENSE_SIZE / SPARSE_STRIDE);

		System.setProperty("rdf4j.lmdb.statementSeek.enabled", "true");
		List<String> withSeek = query(lmdbRepository);

		System.setProperty("rdf4j.lmdb.statementSeek.enabled", "false");
		List<String> withoutSeek = query(lmdbRepository);

		assertThat(withSeek).isEqualTo(baseline);
		assertThat(withoutSeek).isEqualTo(baseline);
	}
}
